#!/usr/bin/env bash
#
# Database Maintenance Toolkit
# Executes SQL maintenance commands securely without eval
#

set -euo pipefail

# Configuration
MYSQL_USER="root"
MYSQL_DEFAULTS_FILE="$HOME/.my.cnf"

# Allowed maintenance commands (whitelist approach)
ALLOWED_PATTERNS=(
    "^ANALYZE TABLE "
    "^OPTIMIZE TABLE "
    "^CHECK TABLE "
    "^REPAIR TABLE "
    "^SHOW "
    "^SELECT .* FROM information_schema\."
    "^FLUSH "
    "^TRUNCATE TABLE "
)

usage() {
    echo "Usage: $0 -d <database> -c <sql_command>"
    echo ""
    echo "Options:"
    echo "  -d    Target database name"
    echo "  -c    SQL command to execute (must be an allowed maintenance command)"
    echo "  -h    Show this help message"
    echo ""
    echo "Allowed command types:"
    echo "  ANALYZE TABLE, OPTIMIZE TABLE, CHECK TABLE, REPAIR TABLE,"
    echo "  SHOW, SELECT from information_schema, FLUSH, TRUNCATE TABLE"
    echo ""
    echo "Note: MySQL credentials should be stored in ~/.my.cnf"
    echo "      [client]"
    echo "      user=root"
    echo "      password=yourpassword"
    exit 1
}

validate_database_name() {
    local db="$1"
    if [[ ! "$db" =~ ^[a-zA-Z0-9_]+$ ]]; then
        echo "ERROR: Invalid database name. Only alphanumeric characters and underscores are allowed." >&2
        exit 1
    fi
}

validate_command() {
    local cmd="$1"
    local upper_cmd
    upper_cmd=$(echo "$cmd" | tr '[:lower:]' '[:upper:]' | sed 's/^[[:space:]]*//')

    # Reject commands containing dangerous characters/patterns
    if [[ "$cmd" =~ [\;\|\&\$\`\\] ]]; then
        echo "ERROR: Command contains disallowed characters (;|&\$\`\\)." >&2
        exit 1
    fi

    # Check against whitelist
    local allowed=false
    for pattern in "${ALLOWED_PATTERNS[@]}"; do
        if [[ "$upper_cmd" =~ $pattern ]]; then
            allowed=true
            break
        fi
    done

    if [[ "$allowed" != "true" ]]; then
        echo "ERROR: Command not in the allowed maintenance commands whitelist." >&2
        echo "Run '$0 -h' to see allowed command types." >&2
        exit 1
    fi
}

log_command() {
    local db="$1"
    local cmd="$2"
    local logfile="/var/log/db_maintenance.log"
    local timestamp
    timestamp=$(date '+%Y-%m-%d %H:%M:%S')
    local log_entry="[$timestamp] USER=$(whoami) DB=$db CMD=\"$cmd\""

    if [[ -w "$logfile" ]] || [[ -w "$(dirname "$logfile")" ]]; then
        echo "$log_entry" >> "$logfile"
    else
        echo "$log_entry" >> "/tmp/db_maintenance.log"
    fi
}

# Parse arguments
DATABASE=""
COMMAND=""

while getopts ":d:c:h" opt; do
    case $opt in
        d) DATABASE="$OPTARG" ;;
        c) COMMAND="$OPTARG" ;;
        h) usage ;;
        \?) echo "ERROR: Invalid option -$OPTARG" >&2; usage ;;
        :) echo "ERROR: Option -$OPTARG requires an argument" >&2; usage ;;
    esac
done

if [[ -z "$DATABASE" ]] || [[ -z "$COMMAND" ]]; then
    echo "ERROR: Both database (-d) and command (-c) are required." >&2
    usage
fi

# Validate inputs
validate_database_name "$DATABASE"
validate_command "$COMMAND"

# Check for MySQL defaults file
if [[ ! -f "$MYSQL_DEFAULTS_FILE" ]]; then
    echo "ERROR: MySQL defaults file not found at $MYSQL_DEFAULTS_FILE" >&2
    echo "Create it with:" >&2
    echo "  [client]" >&2
    echo "  user=root" >&2
    echo "  password=yourpassword" >&2
    echo "Then: chmod 600 $MYSQL_DEFAULTS_FILE" >&2
    exit 1
fi

# Log the command
log_command "$DATABASE" "$COMMAND"

echo "Executing maintenance command on database '$DATABASE'..."
echo "Command: $COMMAND"
echo "---"

# Execute securely — no eval, no password on command line
# The command is passed directly as a parameter to mysql's -e flag
# This is safe because mysql treats it as a SQL string, not a shell command
mysql --defaults-file="$MYSQL_DEFAULTS_FILE" \
    --database="$DATABASE" \
    --batch \
    --table \
    -e "$COMMAND"

exit_code=$?

if [[ $exit_code -eq 0 ]]; then
    echo "---"
    echo "Maintenance command completed successfully."
else
    echo "---"
    echo "ERROR: Command failed with exit code $exit_code." >&2
fi

exit $exit_code